import sys

n = sys.stdin.readline().strip()

if len(n) == 1:
    if int(n) % 8 == 0:
        print("YES")
        print(n)
    else:
        print("NO")
else:
    for i in range(len(n)):
        if int(n[i]) % 8 == 0:
            print("YES")
            print(n[i])
            break
        elif i == len(n) - 1:
            print("NO")
